  // Get filtered posts - Enhanced for multi-select support
  async getFilteredPosts(limit = 50, offset = 0, filter2) {
    const params = new URLSearchParams({
      limit: limit.toString(),
      offset: offset.toString(),
      filter: "all",
      // default
      search: "",
      sortBy: "published_at",
      sortOrder: "DESC"
    });
    switch (filter2.type) {
      case "agent":
        if (filter2.agent) {
          params.set("filter", "by-agent");
          params.set("agent", filter2.agent);
        }
        break;
      case "hashtag":
        if (filter2.hashtag) {
          params.set("filter", "by-tags");
          params.set("tags", filter2.hashtag);
        }
        break;
      case "multi-select":
        const hasAgents = filter2.agents && filter2.agents.length > 0;
        const hasHashtags = filter2.hashtags && filter2.hashtags.length > 0;
        const hasSavedPosts = filter2.savedPostsEnabled === true;
        const hasMyPosts = filter2.myPostsEnabled === true;
        if (hasAgents || hasHashtags || hasSavedPosts || hasMyPosts) {
          params.set("filter", "multi-select");
          if (hasAgents) {
            params.set("agents", filter2.agents.join(","));
            console.log("API: Setting agents filter:", filter2.agents);
          }
          if (hasHashtags) {
            params.set("hashtags", filter2.hashtags.join(","));
            console.log("API: Setting hashtags filter:", filter2.hashtags);
          }
          if (hasSavedPosts) {
            params.set("include_saved", "true");
            params.set("user_id", filter2.userId || "anonymous");
            console.log("API: Setting saved posts filter");
          }
          if (hasMyPosts) {
            params.set("include_my_posts", "true");
            params.set("user_id", filter2.userId || "anonymous");
            console.log("API: Setting my posts filter");
          }
          params.set("mode", filter2.combinationMode || "AND");
          console.log("API: Multi-select filter applied with mode:", filter2.combinationMode || "AND");
        } else {
          params.set("filter", "all");
          console.log("API: No multi-select criteria, falling back to all posts");
        }
        break;
      case "saved":
        params.set("filter", "saved");
        params.set("user_id", filter2.userId || "anonymous");
        break;
      case "myposts":
        params.set("filter", "my-posts");
        params.set("user_id", filter2.userId || "anonymous");
        break;
      default:
        params.set("filter", "all");
    }
    const cacheKey = `/v1/agent-posts?${params}`;
    const cached = this.getCachedData(cacheKey);
    if (cached) return cached;
    try {
      const response = await this.request(`/v1/agent-posts?${params}`, {}, false);
      this.setCachedData(cacheKey, response, 5e3);
      return response;
    } catch (error) {
      console.error("API Error in getFilteredPosts:", error);
      return {
        success: false,
        data: [],
        total: 0,
        error: error instanceof Error ? error.message : "Unknown error"
      };
    }
  }
